import{_ as i,p as a,q as e,Y as l}from"./framework-aa5c4115.js";const t={},r=l('<h1 id="css-面试题" tabindex="-1"><a class="header-anchor" href="#css-面试题" aria-hidden="true">#</a> CSS 面试题</h1><h2 id="为什么用-translate-来改变位置而不是定位" tabindex="-1"><a class="header-anchor" href="#为什么用-translate-来改变位置而不是定位" aria-hidden="true">#</a> 为什么用 translate 来改变位置而不是定位</h2><ul><li>改变 transform 或 opacity 不会触发浏览器重排（reflow）或重绘（repaint），只会触发复合（compositions）。</li><li>⽽改变绝对定位会触发重新布局，进⽽触发重绘和复合。</li><li>transform 使浏览器为元素创建⼀个 GPU 图层，但改变绝对定位会使⽤到 CPU，因此 translate 更⾼效，可以缩短平滑动画的绘制时间。</li><li>translate 改变位置时，元素依然会占据其原始空间，绝对定位就不会发⽣这种情况。</li></ul><h2 id="margin-负值问题" tabindex="-1"><a class="header-anchor" href="#margin-负值问题" aria-hidden="true">#</a> margin 负值问题</h2><ul><li>margin-top 和 margin-left 负值，元素向上、向左移动</li><li>margin-right 负值，右侧元素左移，自身不受影响</li><li>margin-bottom 负值，下方元素上移，自身不受影响</li></ul><h2 id="形成-bfc-的常见条件" tabindex="-1"><a class="header-anchor" href="#形成-bfc-的常见条件" aria-hidden="true">#</a> 形成 BFC 的常见条件</h2><ul><li>float 不是 none</li><li>position 是 absolute 或 fixed</li><li>overflow 不是 visible</li><li>display 是 flex inline-block 等</li></ul>',7),n=[r];function s(o,h){return a(),e("div",null,n)}const d=i(t,[["render",s],["__file","CSSmianshiti.html.vue"]]);export{d as default};
